async function mergeProducts(keepId, mergeIds, mergedBy, reason, tenantId = null) {
  const db = await getDb();
  if (!db) return { merged: 0 };
  const [keepProduct] = await db.select().from(products).where(eq(products.id, keepId)).limit(1);
  if (!keepProduct) throw new Error("Producto principal no encontrado");
  let totalStockAdded = 0;
  for (const mergeId of mergeIds) {
    const [mergeProduct] = await db.select().from(products).where(eq(products.id, mergeId)).limit(1);
    if (!mergeProduct) continue;
    if (mergeProduct.barcode && mergeProduct.barcode !== keepProduct.barcode) {
      try {
        await db.insert(productBarcodes).values({
          productId: keepId,
          barcode: mergeProduct.barcode,
          label: `De: ${mergeProduct.name}`
        });
      } catch (e) {
      }
    }
    await db.update(productBarcodes).set({ productId: keepId }).where(eq(productBarcodes.productId, mergeId));
    await db.update(saleItems).set({ productId: keepId }).where(eq(saleItems.productId, mergeId));
    await db.update(deletedSaleItems).set({ productId: keepId }).where(eq(deletedSaleItems.productId, mergeId));
    await db.update(customerTabItems).set({ productId: keepId }).where(eq(customerTabItems.productId, mergeId));
    await db.update(inventoryAdjustments).set({ productId: keepId }).where(eq(inventoryAdjustments.productId, mergeId));
    await db.update(stockMovements).set({ productId: keepId }).where(eq(stockMovements.productId, mergeId));
    totalStockAdded += mergeProduct.stock;
    await db.update(products).set({ active: false, name: `[FUSIONADO\u2192${keepProduct.name}] ${mergeProduct.name}` }).where(eq(products.id, mergeId));
  }
  if (totalStockAdded > 0) {
    await db.update(products).set({ stock: keepProduct.stock + totalStockAdded }).where(eq(products.id, keepId));
  }
  await db.insert(auditLog).values({
    userId: mergedBy,
    action: "product_merge",
    details: JSON.stringify({
      keepProductId: keepId,
      keepProductName: keepProduct.name,
      mergedProductIds: mergeIds,
      reason,
      totalStockAdded
    })
  });
  return { merged: mergeIds.length, stockAdded: totalStockAdded };
}
async function findSimilarProducts(minSimilarity = 0.6, tenantId = null) {
  const db = await getDb();
  if (!db) return [];
  const dupeRows = await db.execute(sql`
    SELECT LOWER(TRIM(name)) as norm_name,
           GROUP_CONCAT(id ORDER BY id) as ids,
           GROUP_CONCAT(name ORDER BY id SEPARATOR '|||') as names,
           GROUP_CONCAT(COALESCE(barcode, '') ORDER BY id SEPARATOR '|||') as barcodes,
           GROUP_CONCAT(stock ORDER BY id) as stocks,
           GROUP_CONCAT(COALESCE(price, '0') ORDER BY id SEPARATOR '|||') as prices,
           GROUP_CONCAT(COALESCE(brand, '') ORDER BY id SEPARATOR '|||') as brands,
           COUNT(*) as cnt
    FROM products 
    WHERE active = true
    GROUP BY LOWER(TRIM(name))
    HAVING COUNT(*) > 1
    ORDER BY cnt DESC
    LIMIT 50
  `);
  const groups = [];
  for (const row of dupeRows.rows || dupeRows || []) {
    const ids = String(row.ids || "").split(",").map(Number);
    const names = String(row.names || "").split("|||");
    const barcodes = String(row.barcodes || "").split("|||");
    const stocks = String(row.stocks || "").split(",").map(Number);
    const prices = String(row.prices || "").split("|||");
    const brands = String(row.brands || "").split("|||");
    groups.push({
      products: ids.map((id, i) => ({
        id,
        name: names[i] || "",
        barcode: barcodes[i] || null,
        stock: stocks[i] || 0,
        price: prices[i] || "0",
        brand: brands[i] || null,
        categoryId: null
      })),
      similarity: 1,
      reason: "Nombre casi id\xE9ntico"
    });
  }
  return groups;
}
async function getSuspiciousStock(tenantId) {
  const db = await getDb();
  if (!db) return [];
  const allProducts = await db.select({
    id: products.id,
    name: products.name,
    barcode: products.barcode,
    stock: products.stock,
    minStock: products.minStock,
    maxStock: products.maxStock,
    price: products.price,
    cost: products.cost,
    categoryId: products.categoryId
  }).from(products).where(eq(products.active, true));
  const suspicious = [];
  for (const p of allProducts) {
    if (p.stock > p.maxStock * 2 && p.stock > 50) {
      suspicious.push({
        product: p,
        reason: `Stock (${p.stock}) excede el m\xE1ximo (${p.maxStock}) por m\xE1s del doble`,
        severity: "high"
      });
    } else if (p.stock < 0) {
      suspicious.push({
        product: p,
        reason: `Stock negativo (${p.stock})`,
        severity: "high"
      });
    } else if (p.stock > 5e3 && parseFloat(p.price) > 50) {
      suspicious.push({
        product: p,
        reason: `Stock inusualmente alto (${p.stock} unidades)`,
        severity: "medium"
      });
    } else if (p.stock === p.maxStock && p.maxStock === 1e3) {
      suspicious.push({
        product: p,
        reason: `Stock igual al m\xE1ximo predeterminado (${p.stock}) \u2014 posiblemente nunca contado`,
        severity: "low"
      });
    }
  }
  const severityOrder = { high: 0, medium: 1, low: 2 };
  suspicious.sort((a, b) => severityOrder[a.severity] - severityOrder[b.severity]);
  return suspicious;
}
