async function recalculateSaleTotals(saleId, tenantId) {
  const items = await getSaleItems(saleId, tenantId);
  const cartItems = [];
  for (const item of items) {
    const product = await getProductById(item.productId, tenantId);
    cartItems.push({
      id: item.id,
      productId: item.productId,
      productName: item.productName,
      categoryId: product?.categoryId ?? null,
      quantity: parseFloat(item.quantity),
      unitPrice: parseFloat(item.unitPrice),
      originalPrice: parseFloat(item.originalPrice),
      taxRate: parseFloat(item.taxRate)
    });
  }
  const appliedPromos = await evaluatePromotions(cartItems);
  const promoMap = new Map(appliedPromos.map((p) => [p.saleItemId, p]));
  for (const item of items) {
    const promo = promoMap.get(item.id);
    const qty = parseFloat(item.quantity);
    const price = parseFloat(item.unitPrice);
    const taxRate = parseFloat(item.taxRate) / 100;
    const discount = promo ? promo.discountAmount : 0;
    let lineSubtotal;
    let taxAmount2;
    let lineTotal;
    if (item.taxIncluded && taxRate > 0) {
      lineTotal = price * qty - discount;
      lineSubtotal = lineTotal / (1 + taxRate);
      taxAmount2 = lineTotal - lineSubtotal;
    } else {
      lineSubtotal = price * qty - discount;
      taxAmount2 = lineSubtotal * taxRate;
      lineTotal = lineSubtotal + taxAmount2;
    }
    await updateSaleItem(item.id, {
      discount: discount.toFixed(2),
      taxAmount: taxAmount2.toFixed(2),
      lineTotal: lineTotal.toFixed(2),
      promotionId: promo?.promotionId ?? null,
      promotionName: promo?.promotionName ?? null
    }, tenantId);
  }
  const updatedItems = await getSaleItems(saleId);
  let subtotal = 0;
  let taxAmount = 0;
  let discountAmount = 0;
  for (const item of updatedItems) {
    const price = parseFloat(item.unitPrice) * parseFloat(item.quantity);
    const disc = parseFloat(item.discount);
    const itemTax = parseFloat(item.taxAmount);
    if (item.taxIncluded) {
      subtotal += price - disc - itemTax;
    } else {
      subtotal += price - disc;
    }
    taxAmount += itemTax;
    discountAmount += disc;
  }
  const total = subtotal + taxAmount;
  await updateSale(saleId, {
    subtotal: subtotal.toFixed(2),
    taxAmount: taxAmount.toFixed(2),
    discountAmount: discountAmount.toFixed(2),
    total: total.toFixed(2)
  });
}

