import { eq as eq4, and as and4, desc as desc4, gte as gte2 } from "drizzle-orm";
var INITIAL_LOCKOUT_MINUTES = 15;
var MAX_ATTEMPTS = 3;
function calculateLockoutDuration(attemptNumber) {
  if (attemptNumber <= 3) return INITIAL_LOCKOUT_MINUTES;
  if (attemptNumber <= 6) return 30;
  if (attemptNumber <= 9) return 60;
  return 120;
}
async function isPinLocked(tenantId, pin, ipAddress) {
  const db = await getDb();
  if (!db) return { locked: false };
  const recentAttempts = await db.select().from(pinAttempts).where(
    and4(
      eq4(pinAttempts.tenantId, tenantId),
      eq4(pinAttempts.pin, pin),
      eq4(pinAttempts.isSuccessful, false)
    )
  ).orderBy(desc4(pinAttempts.createdAt)).limit(1);
  if (recentAttempts.length === 0) {
    return { locked: false };
  }
  const lastAttempt = recentAttempts[0];
  if (!lastAttempt.lockedUntil) {
    return { locked: false };
  }
  const now = /* @__PURE__ */ new Date();
  if (lastAttempt.lockedUntil > now) {
    const remainingMs = lastAttempt.lockedUntil.getTime() - now.getTime();
    const remainingMinutes = Math.ceil(remainingMs / 6e4);
    return {
      locked: true,
      lockedUntil: lastAttempt.lockedUntil,
      remainingMinutes
    };
  }
  return { locked: false };
}
async function recordFailedPinAttempt(tenantId, pin, userId, ipAddress) {
  const db = await getDb();
  if (!db) return { locked: false, attemptNumber: 0 };
  const yesterday = new Date(Date.now() - 24 * 60 * 60 * 1e3);
  const recentFailures = await db.select().from(pinAttempts).where(
    and4(
      eq4(pinAttempts.tenantId, tenantId),
      eq4(pinAttempts.pin, pin),
      eq4(pinAttempts.isSuccessful, false),
      gte2(pinAttempts.createdAt, yesterday)
    )
  );
  const attemptNumber = recentFailures.length + 1;
  const lockoutMinutes = calculateLockoutDuration(attemptNumber);
  const lockedUntil = new Date(Date.now() + lockoutMinutes * 60 * 1e3);
  await db.insert(pinAttempts).values({
    tenantId,
    userId,
    pin,
    ipAddress,
    isSuccessful: false,
    attemptNumber,
    lockedUntil: attemptNumber >= MAX_ATTEMPTS ? lockedUntil : null
  });
  const shouldLock = attemptNumber >= MAX_ATTEMPTS;
  return {
    locked: shouldLock,
    lockedUntil: shouldLock ? lockedUntil : void 0,
    attemptNumber
  };
}
async function recordSuccessfulPinAttempt(tenantId, pin, userId, ipAddress) {
  const db = await getDb();
  if (!db) return;
  await db.insert(pinAttempts).values({
    tenantId,
    userId,
    pin,
    ipAddress,
    isSuccessful: true,
    attemptNumber: 1
  });
}

