  recordPayment: protectedProcedure.input(z15.object({
    customerId: z15.number(),
    amount: z15.string(),
    reference: z15.string().optional(),
    notes: z15.string().optional()
  })).mutation(async ({ input, ctx }) => {
    const customer = await getCustomerById(input.customerId, ctx.tenantId);
    if (!customer) throw new TRPCError10({ code: "NOT_FOUND", message: "Cliente no encontrado" });
    const paymentAmount = parseFloat(input.amount);
    if (paymentAmount <= 0) throw new TRPCError10({ code: "BAD_REQUEST", message: "Monto debe ser mayor a 0" });
    const currentBalance = parseFloat(customer.creditBalance);
    if (paymentAmount > currentBalance) throw new TRPCError10({ code: "BAD_REQUEST", message: "El pago excede el balance pendiente" });
    const newBalance = currentBalance - paymentAmount;
    await updateCustomer(input.customerId, {
      creditBalance: newBalance.toFixed(2),
      lastPaymentDate: /* @__PURE__ */ new Date()
    });
    await createCreditTransaction({
      customerId: input.customerId,
      type: "payment",
      amount: input.amount,
      balanceAfter: newBalance.toFixed(2),
      reference: input.reference,
      notes: input.notes,
      processedBy: ctx.user.id
    });
    await createAuditEntry({
      userId: ctx.user.id,
      userName: ctx.user.name,
      action: "credit_payment",
      entityType: "customer",
      entityId: input.customerId,
      details: `Pago de RD$${input.amount}. Nuevo balance: RD$${newBalance.toFixed(2)}`
    });
    return { success: true, newBalance: newBalance.toFixed(2) };
  }),
  // Adjust credit balance (admin only)
  adjustBalance: adminProcedure.input(z15.object({
    customerId: z15.number(),
    amount: z15.string(),
    type: z15.enum(["charge", "adjustment"]),
    notes: z15.string()
  })).mutation(async ({ input, ctx }) => {
    const customer = await getCustomerById(input.customerId, ctx.tenantId);
    if (!customer) throw new TRPCError10({ code: "NOT_FOUND", message: "Cliente no encontrado" });
    const adjustAmount = parseFloat(input.amount);
    const currentBalance = parseFloat(customer.creditBalance);
    const newBalance = input.type === "charge" ? currentBalance + adjustAmount : currentBalance + adjustAmount;
    if (newBalance < 0) throw new TRPCError10({ code: "BAD_REQUEST", message: "El balance no puede ser negativo" });
    if (input.type === "charge") {
      const creditLimit = parseFloat(customer.creditLimit);
      if (creditLimit > 0 && newBalance > creditLimit) {
        throw new TRPCError10({ code: "BAD_REQUEST", message: `Excede el l\xEDmite de cr\xE9dito de RD$${creditLimit.toFixed(2)}` });
      }
    }
    await updateCustomer(input.customerId, {
      creditBalance: newBalance.toFixed(2)
    });
    await createCreditTransaction({
      customerId: input.customerId,
      type: input.type,
      amount: input.amount,
      balanceAfter: newBalance.toFixed(2),
      notes: input.notes,
      processedBy: ctx.user.id
    });
    await createAuditEntry({
      userId: ctx.user.id,
      userName: ctx.user.name,
      action: `credit_${input.type}`,
      entityType: "customer",
      entityId: input.customerId,
      details: `${input.type === "charge" ? "Cargo" : "Ajuste"} de RD$${input.amount}. Nuevo balance: RD$${newBalance.toFixed(2)}`
    });
    return { success: true, newBalance: newBalance.toFixed(2) };
  }),
