// server/routers/settings.ts
init_trpc();
init_db();
init_storage();
import { z as z16 } from "zod";
import crypto2 from "crypto";
var settingsRouter = router({
  // Get all settings
  list: protectedProcedure.query(async ({ ctx }) => {
    return getSettings(ctx.tenantId);
  }),
  // Get single setting
  get: protectedProcedure.input(z16.object({
    key: z16.string()
  })).query(async ({ input, ctx }) => {
    return getSetting(input.key, ctx.tenantId);
  }),
  // Update setting (admin only)
  update: adminProcedure.input(z16.object({
    key: z16.string(),
    value: z16.string(),
    description: z16.string().optional()
  })).mutation(async ({ input, ctx }) => {
    await upsertSetting(input.key, input.value, input.description, ctx.tenantId);
    await createAuditEntry({
      userId: ctx.user.id,
      userName: ctx.user.name,
      action: "setting_update",
      entityType: "setting",
      details: `${input.key} = ${input.value}`
    }, ctx.tenantId);
    const branchSyncKeys = ["store_name", "store_address", "store_phone", "receipt_store_name", "receipt_store_address", "receipt_store_phone"];
    if (branchSyncKeys.includes(input.key)) {
      try {
        const allBranches = await getBranches(ctx.tenantId);
        const mainBranch = allBranches.find((b) => b.isMain);
        if (mainBranch) {
          const updates = {};
          if (input.key === "store_name" || input.key === "receipt_store_name") {
            updates.name = input.value + " - Principal";
          }
          if (input.key === "store_address" || input.key === "receipt_store_address") {
            updates.address = input.value;
          }
          if (input.key === "store_phone" || input.key === "receipt_store_phone") {
            updates.phone = input.value;
          }
          if (Object.keys(updates).length > 0) {
            await updateBranch(mainBranch.id, updates, ctx.tenantId);
          }
        }
      } catch (e) {
        console.error("[Settings] Failed to sync main branch:", e);
      }
    }
    return { success: true };
  }),
  // Upload image (for receipt logo, etc.)
  uploadImage: adminProcedure.input(z16.object({
    imageBase64: z16.string(),
    mimeType: z16.string().default("image/png"),
    purpose: z16.string().default("receipt_logo")
  })).mutation(async ({ input, ctx }) => {
    const ext = input.mimeType.includes("png") ? "png" : input.mimeType.includes("webp") ? "webp" : "jpg";
    const hash = crypto2.randomBytes(8).toString("hex");
    const fileKey = `store-images/${input.purpose}-${hash}.${ext}`;
    const buffer = Buffer.from(input.imageBase64, "base64");
    const { url } = await storagePut(fileKey, buffer, input.mimeType);
    if (input.purpose === "receipt_logo") {
      await upsertSetting("receipt_logo_url", url, "Logo del recibo (subido)", ctx.tenantId);
    } else if (input.purpose === "storefront_logo") {
      await upsertSetting("storefront_logo_url", url, "Logo de la tienda en l\xEDnea", ctx.tenantId);
    } else if (input.purpose === "storefront_banner") {
      await upsertSetting("storefront_banner_url", url, "Banner de la tienda en l\xEDnea", ctx.tenantId);
    } else if (input.purpose === "ecf_certificate") {
      await upsertSetting("ecf_p12_certificate_url", url, "Certificado P12 para e-CF", ctx.tenantId);
    } else if (input.purpose === "label_logo") {
      await upsertSetting("label_logo_url", url, "Logo para etiquetas de precio", ctx.tenantId);
    }
    await createAuditEntry({
      userId: ctx.user.id,
      userName: ctx.user.name,
      action: "image_uploaded",
      entityType: "setting",
      details: `${input.purpose}: ${url}`
    }, ctx.tenantId);
    return { url };
  })
});
