// server/routers/loyalty.ts
init_trpc();
init_db();
import { z as z25 } from "zod";
import { TRPCError as TRPCError13 } from "@trpc/server";
var TIER_THRESHOLDS = {
  bronze: 0,
  silver: 500,
  gold: 1500,
  platinum: 5e3
};
var REWARD_THRESHOLD = 100;
function getTierFromPoints(points) {
  if (points >= TIER_THRESHOLDS.platinum) return "platinum";
  if (points >= TIER_THRESHOLDS.gold) return "gold";
  if (points >= TIER_THRESHOLDS.silver) return "silver";
  return "bronze";
}
var loyaltyRouter = router({
  // Get loyalty balance for a customer
  balance: protectedProcedure.input(z25.object({
    customerId: z25.number()
  })).query(async ({ input, ctx }) => {
    const balance = await getLoyaltyBalance(input.customerId, ctx.tenantId);
    return { customerId: input.customerId, balance };
  }),
  // Get loyalty history for a customer
  history: protectedProcedure.input(z25.object({
    customerId: z25.number()
  })).query(async ({ input, ctx }) => {
    return getLoyaltyHistory(input.customerId, ctx.tenantId);
  }),
  // Get customer tier and balance info
  getCustomerInfo: protectedProcedure.input(z25.object({
    customerId: z25.number()
  })).query(async ({ input, ctx }) => {
    const balance = await getLoyaltyBalance(input.customerId, ctx.tenantId);
    const tier = getTierFromPoints(balance);
    const canRedeem = balance >= REWARD_THRESHOLD;
    return {
      customerId: input.customerId,
      balance,
      tier,
      canRedeem,
      rewardThreshold: REWARD_THRESHOLD
    };
  }),
  // Get available rewards
  getAvailableRewards: protectedProcedure.input(z25.object({
    customerId: z25.number()
  })).query(async ({ input, ctx }) => {
    const balance = await getLoyaltyBalance(input.customerId, ctx.tenantId);
    const canRedeem = balance >= REWARD_THRESHOLD;
    const availableRewards = [];
    if (balance >= 100) {
      availableRewards.push({
        id: 1,
        name: "Descuento de RD$100",
        pointsCost: 100,
        description: "Descuento de RD$100 en tu proxima compra"
      });
    }
    if (balance >= 250) {
      availableRewards.push({
        id: 2,
        name: "Descuento de RD$250",
        pointsCost: 250,
        description: "Descuento de RD$250 en tu proxima compra"
      });
    }
    if (balance >= 500) {
      availableRewards.push({
        id: 3,
        name: "Descuento de RD$500",
        pointsCost: 500,
        description: "Descuento de RD$500 en tu proxima compra"
      });
    }
    return {
      canRedeem,
      balance,
      availableRewards
    };
  }),
  // Award points (after a sale) - 1 point per RD$1
  award: protectedProcedure.input(z25.object({
    customerId: z25.number(),
    points: z25.number().min(1),
    saleId: z25.number().optional(),
    reference: z25.string().optional(),
    notes: z25.string().optional()
  })).mutation(async ({ input, ctx }) => {
    const currentBalance = await getLoyaltyBalance(input.customerId, ctx.tenantId);
    const newBalance = currentBalance + input.points;
    const entry = await createLoyaltyEntry({
      customerId: input.customerId,
      type: "earned",
      points: input.points,
      balanceAfter: newBalance,
      saleId: input.saleId,
      reference: input.reference,
      notes: input.notes ?? `${input.points} puntos ganados`,
      createdBy: ctx.user.id
    }, ctx.tenantId);
    return {
      ...entry,
      newBalance,
      tier: getTierFromPoints(newBalance),
      canRedeem: newBalance >= REWARD_THRESHOLD
    };
  }),
  // Redeem points (optional, customer choice)
  redeem: protectedProcedure.input(z25.object({
    customerId: z25.number(),
    points: z25.number().min(1),
    saleId: z25.number().optional(),
    notes: z25.string().optional()
  })).mutation(async ({ input, ctx }) => {
    const currentBalance = await getLoyaltyBalance(input.customerId, ctx.tenantId);
    if (currentBalance < input.points) {
      throw new TRPCError13({ code: "BAD_REQUEST", message: `Puntos insuficientes. Balance actual: ${currentBalance}` });
    }
    const newBalance = currentBalance - input.points;
    const entry = await createLoyaltyEntry({
      customerId: input.customerId,
      type: "redeemed",
      points: -input.points,
      balanceAfter: newBalance,
      saleId: input.saleId,
      notes: input.notes ?? `${input.points} puntos canjeados`,
      createdBy: ctx.user.id
    }, ctx.tenantId);
    return {
      ...entry,
      newBalance,
      discountAmount: input.points,
      // 1 point = RD$1 discount
      tier: getTierFromPoints(newBalance)
    };
  }),
  // Manual adjustment (add or subtract points) - requires reason for audit trail
  adjust: protectedProcedure.input(z25.object({
    customerId: z25.number(),
    points: z25.number(),
    reason: z25.string().min(3, "El motivo debe tener al menos 3 caracteres")
  })).mutation(async ({ input, ctx }) => {
    const currentBalance = await getLoyaltyBalance(input.customerId, ctx.tenantId);
    const newBalance = Math.max(0, currentBalance + input.points);
    const adjustType = input.points > 0 ? "agregados" : "removidos";
    const auditNote = `[Ajuste Manual] ${Math.abs(input.points)} puntos ${adjustType} por ${ctx.user.name || ctx.user.email || "Admin"} \u2014 Motivo: ${input.reason}`;
    await createLoyaltyEntry({
      customerId: input.customerId,
      type: "adjustment",
      points: input.points,
      balanceAfter: newBalance,
      notes: auditNote,
      reference: `ADJ-${Date.now()}`,
      createdBy: ctx.user.id
    });
    try {
      await createAuditEntry({
        userId: ctx.user.id,
        action: "loyalty_adjustment",
        entity: "loyaltyPoints",
        entityId: input.customerId,
        details: JSON.stringify({
          customerId: input.customerId,
          pointsChange: input.points,
          previousBalance: currentBalance,
          newBalance,
          reason: input.reason
        })
      });
    } catch (e) {
      console.error("Error logging loyalty adjustment to audit:", e);
    }
    return { success: true, newBalance, previousBalance: currentBalance };
  }),
  // Delete a specific loyalty entry (with audit trail) - admin only
  deleteEntry: protectedProcedure.input(z25.object({
    entryId: z25.number(),
    customerId: z25.number(),
    reason: z25.string().min(3, "El motivo debe tener al menos 3 caracteres")
  })).mutation(async ({ input, ctx }) => {
    if (ctx.user.role !== "admin") {
      throw new TRPCError13({ code: "FORBIDDEN", message: "Solo administradores pueden eliminar entradas de puntos" });
    }
    const deleted = await deleteLoyaltyEntry(input.entryId, ctx.tenantId);
    if (!deleted) {
      throw new TRPCError13({ code: "NOT_FOUND", message: "Entrada no encontrada" });
    }
    const history = await getLoyaltyHistory(input.customerId, ctx.tenantId);
    const newBalance = await getLoyaltyBalance(input.customerId, ctx.tenantId);
    try {
      await createAuditEntry({
        userId: ctx.user.id,
        action: "loyalty_entry_deleted",
        entity: "loyaltyPoints",
        entityId: input.entryId,
        details: JSON.stringify({
          customerId: input.customerId,
          deletedEntry: {
            type: deleted.type,
            points: deleted.points,
            balanceAfter: deleted.balanceAfter,
            notes: deleted.notes,
            createdAt: deleted.createdAt
          },
          reason: input.reason,
          newBalance
        })
      });
    } catch (e) {
      console.error("Error logging loyalty entry deletion to audit:", e);
    }
    return { success: true, newBalance };
  }),
  // Reset all loyalty points for a customer (with audit trail) - admin only
  resetPoints: protectedProcedure.input(z25.object({
    customerId: z25.number(),
    reason: z25.string().min(3, "El motivo debe tener al menos 3 caracteres")
  })).mutation(async ({ input, ctx }) => {
    if (ctx.user.role !== "admin") {
      throw new TRPCError13({ code: "FORBIDDEN", message: "Solo administradores pueden resetear puntos" });
    }
    const currentBalance = await getLoyaltyBalance(input.customerId, ctx.tenantId);
    await resetLoyaltyPoints(input.customerId, ctx.tenantId);
    try {
      await createAuditEntry({
        userId: ctx.user.id,
        action: "loyalty_points_reset",
        entity: "loyaltyPoints",
        entityId: input.customerId,
        details: JSON.stringify({
          customerId: input.customerId,
          previousBalance: currentBalance,
          reason: input.reason,
          resetBy: ctx.user.name || ctx.user.email
        })
      });
    } catch (e) {
      console.error("Error logging loyalty reset to audit:", e);
    }
    return { success: true, previousBalance: currentBalance };
  })
});

