// server/routers/priceAdjustments.ts
init_trpc();
init_db();
init_notification();
import { z as z31 } from "zod";
import { TRPCError as TRPCError14 } from "@trpc/server";
async function applyAdjustment(adj, approvedById, approvedByReason, tenantId) {
  const items = await getSaleItems(adj.saleId, tenantId);
  const item = items.find((i) => i.id === adj.saleItemId);
  if (!item) return;
  const newPrice = parseFloat(adj.newPrice);
  const qty = parseFloat(item.quantity);
  const taxRate = parseFloat(item.taxRate) / 100;
  const discountAmount = (parseFloat(adj.originalPrice) - newPrice) * qty;
  let lineSubtotal;
  let taxAmount;
  let lineTotal;
  if (item.taxIncluded && taxRate > 0) {
    lineTotal = newPrice * qty;
    lineSubtotal = lineTotal / (1 + taxRate);
    taxAmount = lineTotal - lineSubtotal;
  } else {
    lineSubtotal = newPrice * qty;
    taxAmount = lineSubtotal * taxRate;
    lineTotal = lineSubtotal + taxAmount;
  }
  await updateSaleItem(adj.saleItemId, {
    unitPrice: newPrice.toFixed(2),
    discount: discountAmount.toFixed(2),
    taxAmount: taxAmount.toFixed(2),
    lineTotal: lineTotal.toFixed(2),
    overrideApprovedBy: approvedById,
    overrideReason: approvedByReason
  }, tenantId);
  const allItems = await getSaleItems(adj.saleId, tenantId);
  let subtotal = 0;
  let totalTax = 0;
  let totalDiscount = 0;
  for (const si of allItems) {
    const siPrice = parseFloat(si.unitPrice) * parseFloat(si.quantity);
    const siDisc = parseFloat(si.discount);
    const siTax = parseFloat(si.taxAmount);
    if (si.taxIncluded) {
      subtotal += siPrice - siDisc - siTax;
    } else {
      subtotal += siPrice - siDisc;
    }
    totalTax += siTax;
    totalDiscount += siDisc;
  }
  const total = subtotal + totalTax;
  await updateSale(adj.saleId, {
    subtotal: subtotal.toFixed(2),
    taxAmount: totalTax.toFixed(2),
    discountAmount: totalDiscount.toFixed(2),
    total: total.toFixed(2)
  });
}
var priceAdjustmentsRouter = router({
  // Cashier requests a price adjustment on a cart item
  request: protectedProcedure.input(z31.object({
    saleId: z31.number(),
    saleItemId: z31.number(),
    productName: z31.string(),
    adjustmentType: z31.enum(["discount_percent", "discount_amount", "new_price"]),
    adjustmentValue: z31.number().positive(),
    originalPrice: z31.number().positive(),
    reason: z31.string().min(1, "Debe indicar una raz\xF3n")
  })).mutation(async ({ input, ctx }) => {
    let newPrice;
    if (input.adjustmentType === "discount_percent") {
      newPrice = input.originalPrice * (1 - input.adjustmentValue / 100);
    } else if (input.adjustmentType === "discount_amount") {
      newPrice = input.originalPrice - input.adjustmentValue;
    } else {
      newPrice = input.adjustmentValue;
    }
    if (newPrice < 0) newPrice = 0;
    const result = await createPriceAdjustment({
      saleId: input.saleId,
      saleItemId: input.saleItemId,
      productName: input.productName,
      adjustmentType: input.adjustmentType,
      adjustmentValue: input.adjustmentValue.toFixed(2),
      originalPrice: input.originalPrice.toFixed(2),
      newPrice: newPrice.toFixed(2),
      reason: input.reason,
      requestedBy: ctx.user.id,
      requestedByName: ctx.user.name || void 0
    });
    await createAuditEntry({
      userId: ctx.user.id,
      userName: ctx.user.name,
      action: "price_adjustment_requested",
      entityType: "priceAdjustment",
      entityId: result?.id,
      details: JSON.stringify({
        saleId: input.saleId,
        product: input.productName,
        type: input.adjustmentType,
        value: input.adjustmentValue,
        originalPrice: input.originalPrice,
        newPrice,
        reason: input.reason
      })
    });
    notifyOwner({
      title: "\u{1F514} Solicitud de Ajuste de Precio",
      content: `${ctx.user.name || "Cajero"} solicita ajuste en ${input.productName}: RD$${input.originalPrice.toFixed(2)} \u2192 RD$${newPrice.toFixed(2)}. Raz\xF3n: ${input.reason}. Revise en Aprobaciones.`
    }).catch(() => {
    });
    notifyAdmins({
      type: "price_adjustment",
      title: "Ajuste de Precio Solicitado",
      message: `${ctx.user.name || "Cajero"} solicita ajuste en ${input.productName}: RD$${input.originalPrice.toFixed(2)} \u2192 RD$${newPrice.toFixed(2)}`,
      actionUrl: "/overrides"
    }).catch(() => {
    });
    return { id: result?.id, newPrice };
  }),
  // Admin/manager approves or rejects
  resolve: protectedProcedure.input(z31.object({
    id: z31.number(),
    action: z31.enum(["approved", "rejected"])
  })).mutation(async ({ input, ctx }) => {
    if (ctx.user.role !== "admin" && ctx.user.role !== "manager") {
      throw new TRPCError14({ code: "FORBIDDEN", message: "Solo admin/gerente puede aprobar ajustes" });
    }
    const adj = await getPriceAdjustmentById(input.id, ctx.tenantId);
    if (!adj) throw new TRPCError14({ code: "NOT_FOUND" });
    if (adj.status !== "pending") throw new TRPCError14({ code: "BAD_REQUEST", message: "Este ajuste ya fue procesado" });
    await resolvePriceAdjustment(input.id, input.action, ctx.user.id, ctx.user.name || void 0, ctx.tenantId);
    if (input.action === "approved") {
      await applyAdjustment(adj, ctx.user.id, adj.reason, ctx.tenantId);
    }
    await createAuditEntry({
      userId: ctx.user.id,
      userName: ctx.user.name,
      action: `price_adjustment_${input.action}`,
      entityType: "priceAdjustment",
      entityId: input.id,
      details: JSON.stringify({ product: adj.productName, originalPrice: adj.originalPrice, newPrice: adj.newPrice })
    });
    return { success: true };
  }),
  // Quick approve with PIN (for in-person manager override at POS)
  quickApprove: protectedProcedure.input(z31.object({
    id: z31.number(),
    managerPin: z31.string().min(1)
  })).mutation(async ({ input, ctx }) => {
    const manager = await getUserByPin(input.managerPin, ctx.tenantId);
    if (!manager || manager.role !== "admin" && manager.role !== "manager") {
      throw new TRPCError14({ code: "FORBIDDEN", message: "PIN inv\xE1lido o no tiene permisos de gerente" });
    }
    const adj = await getPriceAdjustmentById(input.id, ctx.tenantId);
    if (!adj) throw new TRPCError14({ code: "NOT_FOUND" });
    if (adj.status !== "pending") throw new TRPCError14({ code: "BAD_REQUEST", message: "Este ajuste ya fue procesado" });
    await resolvePriceAdjustment(input.id, "approved", manager.id, manager.name || void 0, ctx.tenantId);
    await applyAdjustment(adj, manager.id, adj.reason);
    await createAuditEntry({
      userId: manager.id,
      userName: manager.name,
      action: "price_adjustment_quick_approved",
      entityType: "priceAdjustment",
      entityId: input.id,
      details: JSON.stringify({ product: adj.productName, originalPrice: adj.originalPrice, newPrice: adj.newPrice })
    });
    return { success: true, approvedBy: manager.name };
  }),
  // List pending adjustments (for admin approval queue)
  pending: protectedProcedure.query(async ({ ctx }) => {
    if (ctx.user.role !== "admin" && ctx.user.role !== "manager") {
      throw new TRPCError14({ code: "FORBIDDEN" });
    }
    return getPendingAdjustments(ctx.tenantId);
  }),
  // Get adjustments for a specific sale
  forSale: protectedProcedure.input(z31.object({
    saleId: z31.number()
  })).query(async ({ input, ctx }) => {
    return getAdjustmentsForSale(input.saleId, ctx.tenantId);
  })
});

