init_twilioMessaging();
init_storage();
import { z as z35 } from "zod";
import { TRPCError as TRPCError16 } from "@trpc/server";
import crypto3 from "crypto";
function getNotificationChannel(settings) {
  if (settings.whatsappNotificationsEnabled && settings.smsNotificationsEnabled) return "both";
  if (settings.whatsappNotificationsEnabled) return "whatsapp";
  if (settings.smsNotificationsEnabled) return "sms";
  return null;
}
function isNotificationEnabled(settings, status) {
  switch (status) {
    case "placed":
      return settings.notifyOnOrderPlaced;
    case "confirmed":
      return settings.notifyOnOrderConfirmed;
    case "preparing":
      return settings.notifyOnOrderConfirmed;
    // grouped with confirmed
    case "ready":
      return settings.notifyOnOrderReady;
    case "out_for_delivery":
      return settings.notifyOnOrderDelivery;
    case "delivered":
      return settings.notifyOnOrderDelivery;
    case "picked_up":
      return settings.notifyOnOrderDelivery;
    case "cancelled":
      return settings.notifyOnOrderCancelled;
    default:
      return false;
  }
}
async function sendNotificationIfEnabled(status, orderData, items, tenantId) {
  try {
    const settings = await getStoreSettings(tenantId);
    if (!settings) return;
    const channel = getNotificationChannel(settings);
    if (!channel) return;
    if (!isNotificationEnabled(settings, status)) return;
    const notifData = {
      orderNumber: orderData.orderNumber,
      customerName: orderData.customerName,
      customerPhone: orderData.customerPhone,
      total: orderData.total,
      deliveryType: orderData.deliveryType,
      paymentMethod: orderData.paymentMethod,
      storeName: settings.storeName || "Mi Supermercado",
      items: items?.map((i) => ({
        productName: i.productName,
        quantity: i.quantity,
        unitPrice: i.unitPrice
      })),
      cancelReason: orderData.cancelReason
    };
    const result = await sendOrderNotification(status, notifData, channel);
    const notifChannel = result.whatsapp?.success ? "whatsapp" : result.sms?.success ? "sms" : null;
    if (notifChannel) {
      await updateOnlineOrderNotification(orderData.id, status, notifChannel, tenantId);
    }
  } catch (err) {
    console.error("[Notification] Error sending order notification:", err);
  }
}
