// server/_core/context.ts
async function createContext(opts) {
  let user = null;
  try {
    user = await sdk.authenticateRequest(opts.req);
  } catch (error) {
    user = null;
  }
  const machineId = opts.req.headers["x-machine-id"] || null;
  const machineName = opts.req.headers["x-machine-name"] || null;
  return {
    req: opts.req,
    res: opts.res,
    user,
    tenantId: user?.tenantId ?? null,
    machineId,
    machineName
  };
}

